select.if:
select c.id, c.site_id, c.parent_id, c.name, c.category_type, c.slug, c.icon, c.description, c.sort_order, c.status, c.del_flag, c.create_by, c.create_time, c.update_by, c.update_time, -- 统一的可见性状态： -- 1. 自有分类（site_id = 当前网站）：优先使用关联表的is_visible（如果存在），否则使用分类本身的status -- 2. 默认配置（site_id = 0）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站分类：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN c.site_id = #{siteId} THEN IFNULL(incl.is_visible, c.status) WHEN c.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识：own(自己的) | default(默认配置) | shared(其他网站分享) CASE WHEN c.site_id = #{siteId} THEN 'own' WHEN c.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN c.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded, (select count(*) from gb_site_category_relations r2 where r2.category_id = c.id AND r2.relation_type = 'include') as related_sites_count, (select count(*) from gb_site_category_relations r3 where r3.category_id = c.id AND r3.relation_type = 'exclude') as excluded_sites_count, -- 统计关联数据个数（关联模式下使用与查询列表相同的逻辑） (CASE c.category_type WHEN 'game' THEN ( SELECT COUNT(DISTINCT g.id) FROM gb_games g LEFT JOIN gb_game_category_relations gcr ON g.id = gcr.game_id LEFT JOIN gb_site_game_relations g_incl ON g.id = g_incl.game_id AND g_incl.site_id = #{siteId} AND g_incl.relation_type = 'include' LEFT JOIN gb_site_game_relations g_excl ON g.id = g_excl.game_id AND g_excl.site_id = #{siteId} AND g_excl.relation_type = 'exclude' WHERE g.del_flag = '0' AND gcr.category_id = c.id AND ( g.site_id = #{siteId} OR (g.site_id = #{params.personalSiteId} AND g_excl.id IS NULL) OR (g.site_id != #{siteId} AND g.site_id != 0 AND g_incl.id IS NOT NULL) ) ) WHEN 'gamebox' THEN ( SELECT COUNT(DISTINCT gb.id) FROM gb_game_boxes gb LEFT JOIN gb_box_category_relations bcr ON gb.id = bcr.box_id LEFT JOIN gb_site_box_relations gb_incl ON gb.id = gb_incl.box_id AND gb_incl.site_id = #{siteId} AND gb_incl.relation_type = 'include' LEFT JOIN gb_site_box_relations gb_excl ON gb.id = gb_excl.box_id AND gb_excl.site_id = #{siteId} AND gb_excl.relation_type = 'exclude' WHERE gb.del_flag = '0' AND (gb.category_id = c.id OR bcr.category_id = c.id) AND ( gb.site_id = #{siteId} OR (gb.site_id = #{params.personalSiteId} AND gb_excl.id IS NULL) OR (gb.site_id != #{siteId} AND gb.site_id != 0 AND gb_incl.id IS NOT NULL) ) ) WHEN 'article' THEN ( SELECT COUNT(*) FROM gb_master_articles ma LEFT JOIN gb_site_master_article_relations a_incl ON ma.id = a_incl.master_article_id AND a_incl.site_id = #{siteId} AND a_incl.relation_type = 'include' LEFT JOIN gb_site_master_article_relations a_excl ON ma.id = a_excl.master_article_id AND a_excl.site_id = #{siteId} AND a_excl.relation_type = 'exclude' WHERE ma.category_id = c.id AND ma.del_flag = '0' AND ( ma.site_id = #{siteId} OR (ma.site_id = #{params.personalSiteId} AND a_excl.id IS NULL) OR (ma.site_id != #{siteId} AND ma.site_id != 0 AND a_incl.id IS NOT NULL) ) ) WHEN 'website' THEN ( SELECT COUNT(*) FROM gb_sites s WHERE s.category_id = c.id AND s.del_flag = '0' ) WHEN 'storage' THEN ( SELECT COUNT(*) FROM gb_storage_configs sc WHERE sc.category_id = c.id AND sc.del_flag = '0' ) WHEN 'ai_platform' THEN ( SELECT COUNT(DISTINCT ap.id) FROM gb_ai_platforms ap LEFT JOIN gb_site_platform_relations ap_incl ON ap.id = ap_incl.platform_id AND ap_incl.site_id = #{siteId} AND ap_incl.relation_type = 'include' LEFT JOIN gb_site_platform_relations ap_excl ON ap.id = ap_excl.platform_id AND ap_excl.site_id = #{siteId} AND ap_excl.relation_type = 'exclude' WHERE ap.category_id = c.id AND ap.del_flag = '0' AND ( ap.site_id = #{siteId} OR (ap.site_id = #{params.personalSiteId} AND ap_excl.id IS NULL) OR (ap.site_id != #{siteId} AND ap.site_id != 0 AND ap_incl.id IS NOT NULL) ) ) WHEN 'atomic_tool' THEN ( SELECT COUNT(DISTINCT at.id) FROM gb_atomic_tool at LEFT JOIN gb_site_atomic_tool_relations at_incl ON at.id = at_incl.tool_id AND at_incl.site_id = #{siteId} AND at_incl.relation_type = 'include' LEFT JOIN gb_site_atomic_tool_relations at_excl ON at.id = at_excl.tool_id AND at_excl.site_id = #{siteId} AND at_excl.relation_type = 'exclude' WHERE at.category_id = c.id AND at.enabled = '1' AND ( at.site_id = #{siteId} OR (at.site_id = #{params.personalSiteId} AND at_excl.id IS NULL) OR (at.site_id != #{siteId} AND at.site_id != 0 AND at_incl.id IS NOT NULL) ) ) WHEN 'workflow' THEN ( SELECT COUNT(DISTINCT wf.id) FROM gb_workflow wf LEFT JOIN gb_site_workflow_relation wf_incl ON wf.id = wf_incl.workflow_id AND wf_incl.site_id = #{siteId} AND wf_incl.relation_type = 'include' LEFT JOIN gb_site_workflow_relation wf_excl ON wf.id = wf_excl.workflow_id AND wf_excl.site_id = #{siteId} AND wf_excl.relation_type = 'exclude' WHERE wf.category_id = c.id AND wf.enabled = 1 AND ( wf.site_id = #{siteId} OR (wf.site_id = #{params.personalSiteId} AND wf_excl.id IS NULL) OR (wf.site_id != #{siteId} AND wf.site_id != 0 AND wf_incl.id IS NOT NULL) ) ) WHEN 'title_pool' THEN ( SELECT COUNT(*) FROM gb_title_pool_batch b WHERE b.category_id = c.id AND b.status = '1' AND (b.site_id = #{siteId} OR b.site_id = #{params.personalSiteId}) ) ELSE 0 END) as related_data_count from gb_categories c -- 左连接正向关联（include） LEFT JOIN gb_site_category_relations incl ON c.id = incl.category_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_category_relations excl ON c.id = excl.category_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
c.del_flag = '0'
AND ( c.site_id = #{siteId}
OR c.site_id = #{params.personalSiteId}
OR (c.site_id != #{siteId}
AND c.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) and c.parent_id = #{parentId} and c.name like concat('%', #{name}, '%') and c.category_type = #{categoryType} and c.is_section = #{isSection} and c.status = #{status}
order by c.parent_id, c.sort_order asc, c.create_time desc

choose.when:
select c.id, c.site_id, c.parent_id, c.name, c.category_type, c.slug, c.icon, c.description, c.sort_order, c.status, c.del_flag, c.create_by, c.create_time, c.update_by, c.update_time, CASE WHEN c.site_id = #{siteId} THEN c.status WHEN c.site_id = #{params.personalSiteId} THEN (CASE WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, CASE WHEN c.site_id = #{siteId} THEN 'own' WHEN c.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source from gb_categories c LEFT JOIN gb_site_category_relations incl ON c.id = incl.category_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' LEFT JOIN gb_site_category_relations excl ON c.id = excl.category_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
c.del_flag = '0' AND (
(c.site_id = #{siteId} AND c.status = '1') OR
(c.site_id = #{params.personalSiteId} AND excl.id IS NULL) OR
(c.site_id != #{siteId}
AND c.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL AND incl.is_visible = '1') ) and c.parent_id = #{parentId} and c.name like concat('%', #{name}, '%') and c.category_type = #{categoryType}
order by c.parent_id, c.sort_order asc, c.create_time desc

choose.otherwise:



    del_flag = '0' and status = '1'


            and site_id = #{params.personalSiteId}


            and 1=0


     and parent_id = #{parentId}
     and name like concat('%', #{name}, '%')
     and category_type = #{categoryType}

order by sort_order asc, create_time desc

mapper.update:
update gb_categories
site_id = #{siteId}, parent_id = #{parentId}, name = #{name}, category_type = #{categoryType}, is_section = #{isSection}, slug = #{slug}, icon = #{icon}, description = #{description}, sort_order = #{sortOrder}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime},
where id = #{id}

mapper.select:
SELECT DISTINCT c.*, scr.is_visible as site_is_visible, scr.sort_order as site_sort_order, (select count(*) from gb_site_category_relations r where r.category_id = c.id) as related_sites_count FROM gb_categories c INNER JOIN gb_site_category_relations scr ON c.id = scr.category_id AND scr.site_id = #{siteId} WHERE c.status = '1' AND c.del_flag = '0' AND scr.is_visible = '1'
AND c.category_type = #{categoryType}
AND c.parent_id = #{parentId}
ORDER BY scr.sort_order ASC, c.sort_order ASC
